-- 一、單位對照表 (unit_map)
CREATE TABLE unit_map (district_code CHAR(7), unit_code CHAR(7), person_id CHAR(7), PRIMARY KEY (person_id));

-- 二、缺勤表 (absence)
CREATE TABLE absence (unit_code CHAR(7), person_id CHAR(7), absence_date DATE, PRIMARY KEY (person_id, absence_date));

-- 三、事假表 (personal_leave)
CREATE TABLE personal_leave (unit_code CHAR(7), person_id CHAR(7), leave_date DATE, PRIMARY KEY (person_id, leave_date));

-- 四、病假表 (sick_leave)
CREATE TABLE sick_leave (unit_code CHAR(7), person_id CHAR(7), leave_date DATE, PRIMARY KEY (person_id, leave_date));


